,p_plug_name=>'Etiquetas'
,p_static_id=>'etiquetas'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>10
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT e.id_etiqueta,',
'       u.nombre_usuario,',
'       e.nombre AS etiqueta,',
'       e.color,',
'       p.titulo AS pelicula',
'FROM etiqueta e',
'JOIN usuario u ON u.id_usuario = e.id_usuario',
'LEFT JOIN pelicula_etiqueta pe ON pe.id_etiqueta = e.id_etiqueta',
'LEFT JOIN pelicula p ON p.id_pelicula = pe.id_pelicula',
'ORDER BY u.nombre_usuario, e.nombre'))
